module multi_8bit
(
    input [7:0] A,
    input [7:0] B,
    output [15:0] product
);

    reg [15:0] partial_product;
    reg [3:0] shift_count;
    reg [7:0] multiplier;
    reg [15:0] accumulator;

    always @(*) begin
        partial_product = 16'b0;
        shift_count = 4'b0;
        multiplier = B;
        accumulator = 16'b0;

        for (shift_count = 0; shift_count < 8; shift_count = shift_count + 1) begin
            if (multiplier[0] == 1'b1) begin
                accumulator = accumulator + (A << shift_count);
            end
            multiplier = multiplier >> 1;
        end

        partial_product = accumulator;
    end

    assign product = partial_product;

endmodule
